    val nn = n.toInt
    val kk = k.toInt
    val maxW = if (edges.isEmpty) 0L else edges.map(e => e(2)).max

    var low: Long = 0
    var high: Long = maxW

    def isValid(x: Long): Boolean = {
        val parent = (0 until nn).toArray
        val rank = Array.fill(nn)(0)

        def find(a: Int): Int = {
            if (parent(a) != a) {
                parent(a) = find(parent(a))
            }
            parent(a)
        }

        def union(a: Int, b: Int): Unit = {
            val ra = find(a)
            val rb = find(b)
            if (ra != rb) {
                if (rank(ra) < rank(rb)) {
                    parent(ra) = rb
                } else if (rank(ra) > rank(rb)) {
                    parent(rb) = ra
                } else {
                    parent(rb) = ra
                    rank(ra) += 1
                }
