        var components = 0
        for (i <- 0 until nn) {
            if (parent(i) == i) components += 1
        }
        components <= kk
    }

    while (low < high) {
        val mid = (low + high) / 2
        if (isValid(mid)) {
            high = mid
        } else {
            low = mid + 1
        }
