def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
    val numNodes = n.toInt
    val maxWeight = if (edges.nonEmpty) edges.map(_(2)).max else 0L
    var low = 0L
    var high = maxWeight

    while (low < high) {
        val mid = (low + high) / 2
        val parent = (0 until numNodes).toArray
        val rank = Array.fill(numNodes)(0)
        var compCount = numNodes

        def find(x: Int): Int = {
            var root = x
            while (root != parent(root)) {
                root = parent(root)
            }
            var curr = x
            while (curr != root) {
                val next = parent(curr)
                parent(curr) = root
                curr = next
            }
            root
        }

        def union(x: Int, y: Int): Unit = {
            val rx = find(x)
            val ry = find(y)
            if (rx != ry) {
                if (rank(rx) < rank(ry)) {
                    parent(rx) = ry
                } else if (rank(rx) > rank(ry)) {
                    parent(ry) = rx
                } else {
                    parent(ry) = rx
                    rank(rx) += 1
                }
                compCount -= 1
            }
        }

        for (edge <- edges) {
            val u = edge(0).toInt
            val v = edge(1).toInt
            val w = edge(2)
            if (w <= mid) {
                union(u, v)
            }
        }

        if (compCount <= k) {
            high = mid
        } else {
            low = mid + 1
        }
    }

    low
}
```

### Explanation
1. **Binary Search Setup**: The binary search is initialized with `low` set to 0 and `high` set to the maximum edge weight in the graph. This range represents the possible values for the maximum cost in any connected component.
2. **DSU for Component Counting**: For each midpoint `mid` in the binary search, we use DSU to count the number of connected components when only edges with weights ≤ `mid` are considered. The DSU efficiently unions nodes connected by such edges and tracks the number of components.
3. **Feasibility Check**: If the number of connected components is ≤ `k`, it means `mid` is a feasible solution, and we adjust the upper bound `high` to `mid` to search for a smaller feasible value. Otherwise, we adjust `low` to `mid + 1`.
4. **Result Extraction**: The loop exits when `low` equals `high`, which gives the smallest feasible maximum cost that satisfies the condition of having at most `k` connected components.

This approach efficiently narrows down the solution space using binary search and leverages DSU for dynamic connectivity checks, ensuring optimal performance even for large graphs.
